import { TimeseriesClosestPoint } from './find-closest-points.js';

/**
 * Sort the Tooltip items to keep the visual consistency with the plot
 * @param xPoints - An array of TimeseriesClosestPoint
 * @returns a TimeseriesClosesPoint array reference sorted
 **/
export const sortTooltipItems = (xPoints: TimeseriesClosestPoint[]) => {
  return xPoints.sort((p1, p2) => p1.y - p2.y);
};
